from dataclasses import dataclass
from pathlib import Path

@dataclass(frozen=True)
class StorageTier:
    name: str
    encrypted: bool
    key_management: str
    access_control: str
    max_label: SensitivityLevel

STORAGE_TIERS = {
    "public_cache":    StorageTier("public_cache",    False, "none",         "open",        SensitivityLevel.INTERNAL),
    "encrypted_store": StorageTier("encrypted_store", True,  "cmk",          "rbac",        SensitivityLevel.RESTRICTED),
    "regulated_vault": StorageTier("regulated_vault", True,  "byok_hsm",     "named_user",  SensitivityLevel.REGULATED),
}

def assign_storage_tier(label: SensitivityLevel) -> StorageTier:
    if label <= SensitivityLevel.INTERNAL:
        return STORAGE_TIERS["public_cache"]
    if label <= SensitivityLevel.RESTRICTED:
        return STORAGE_TIERS["encrypted_store"]
    return STORAGE_TIERS["regulated_vault"]


@dataclass
class StoredArtifact:
    trace_id: str
    label: SensitivityLevel
    storage_tier: StorageTier
    encryption_key_id: str
    access_group: str

    @classmethod
    def create(cls, trace_id: str, label: SensitivityLevel,
               key_id: str, access_group: str) -> "StoredArtifact":
        return cls(
            trace_id=trace_id,
            label=label,
            storage_tier=assign_storage_tier(label),
            encryption_key_id=key_id,
            access_group=access_group,
        )

    def can_export(self, requestor_clearance: SensitivityLevel) -> bool:
        """Data may only be exported by users cleared at or above its label."""
        return requestor_clearance >= self.label

from dataclasses import dataclass, field
from enum import IntEnum

class ClearanceLevel(IntEnum):
    GENERAL    = 0   # all employees
    NEED_KNOW  = 1   # specific business function groups
    NAMED      = 2   # explicitly named in ACL
    REGULATED  = 3   # named + regulatory compliance verified

@dataclass
class UserClearance:
    user_id: str
    clearance: ClearanceLevel
    max_label: SensitivityLevel    # highest classification this user may access
    groups: list[str] = field(default_factory=list)
    acl_entries: list[str] = field(default_factory=list)  # artifact IDs explicitly granted

def can_access(user: UserClearance,
               artifact_label: SensitivityLevel,
               artifact_id: str | None = None) -> tuple[bool, str]:
    """Return (allowed, reason)."""
    if user.max_label < artifact_label:
        return False, f"User clearance {user.max_label.name} < artifact {artifact_label.name}"

    if artifact_label == SensitivityLevel.RESTRICTED:
        if artifact_id and artifact_id not in user.acl_entries:
            if user.clearance < ClearanceLevel.NAMED:
                return False, "RESTRICTED requires named ACL entry"

    if artifact_label == SensitivityLevel.REGULATED:
        if user.clearance < ClearanceLevel.REGULATED:
            return False, "REGULATED requires regulatory clearance"
        if artifact_id and artifact_id not in user.acl_entries:
            return False, "REGULATED requires explicit ACL grant"

    return True, "access granted"
